139	// AdvRefsCaps returns the sorted capability list from an AdvRefs.
140	func AdvRefsCaps(adv *packp.AdvRefs) []string {
141		if adv == nil || adv.Capabilities == nil {
142			return nil
143		}
144		all := adv.Capabilities.All()
145		items := make([]string, 0, len(all))
146		for _, cap := range all {
147			values := adv.Capabilities.Get(cap)
148			if len(values) == 0 {
149				items = append(items, string(cap))
150				continue
151			}
152			for _, value := range values {
153				items = append(items, string(cap)+"="+value)
154			}
155		}
156		return items
157	}
