171	func listSourceRefsV2(ctx context.Context, conn Conn, caps *V2Capabilities, prefixes []string) ([]*plumbing.Reference, plumbing.ReferenceName, error) {
172		// Always include "HEAD" so the server returns the symref-target attribute
173		// for HEAD. Without this, callers that pass only "refs/heads/" or
174		// "refs/tags/" prefixes filter HEAD out of the response and lose the
175		// default-branch hint that bootstrap planning uses as a trunk cutoff.
176		args := []string{"peel", "symrefs", "ref-prefix HEAD"}
177		for _, prefix := range prefixes {
178			args = append(args, "ref-prefix "+prefix)
179		}
180		body, err := EncodeCommand("ls-refs", caps.RequestCapabilities(), args)
181		if err != nil {
182			return nil, "", err
183		}
184		data, err := PostRPC(ctx, conn, transport.UploadPackService, body, true, "upload-pack ls-refs")
185		if err != nil {
186			return nil, "", err
187		}
188		return decodeV2LSRefs(bytes.NewReader(data))
189	}

