19	// RefService encapsulates the result of source ref discovery and the negotiated
20	// protocol, providing methods for subsequent fetch and pack operations.
21	type RefService struct {
22		Protocol string // "v1" or "v2"
23		V1Adv    *packp.AdvRefs
24		V2Caps   *V2Capabilities
25		// HeadTarget is the branch that HEAD points to on the source, when
26		// advertised as a symref. Empty for detached HEAD or when the source
27		// does not advertise symref information.
28		HeadTarget plumbing.ReferenceName
29		// Verbose, when true, streams source-side sideband progress ("Counting
30		// objects", "Compressing objects", ...) to stderr and asks the source
31		// upload-pack to emit progress by not sending the no-progress option.
32		Verbose bool
33	}
