35	// ListSourceRefs discovers refs from the source using the configured protocol mode.
36	// Returns the list of refs and a RefService for subsequent operations.
37	func ListSourceRefs(ctx context.Context, conn Conn, protocolMode string, refPrefixes []string) ([]*plumbing.Reference, *RefService, error) {
38		switch protocolMode {
39		case "v1":
40			adv, refs, err := listSourceRefsV1(ctx, conn)
41			if err != nil {
42				return nil, nil, err
43			}
44			return refs, &RefService{Protocol: "v1", V1Adv: adv, HeadTarget: headTargetFromAdv(adv)}, nil
45	
46		case "auto", "v2":
47			data, err := RequestInfoRefs(ctx, conn, transport.UploadPackService, "version=2")
48			if err != nil {
49				if protocolMode == "auto" && shouldFallbackToV1AfterV2ProbeError(conn, err) {
50					return listSourceRefsAutoV1(ctx, conn)
51				}
52				return nil, nil, err
53			}
54			if caps, err := DecodeV2Capabilities(bytes.NewReader(data)); err == nil {
55				if !caps.Supports("ls-refs") || !caps.Supports("fetch") {
56					return nil, nil, errors.New("source does not advertise required protocol v2 commands")
57				}
58				refs, headTarget, err := listSourceRefsV2(ctx, conn, caps, refPrefixes)
59				if err != nil {
60					return nil, nil, err
61				}
62				return refs, &RefService{Protocol: "v2", V2Caps: caps, HeadTarget: headTarget}, nil
63			}
64			if protocolMode == "v2" {
65				return nil, nil, errors.New("source did not negotiate protocol v2")
66			}
67			// Fall back to v1
68			adv, err := decodeV1AdvRefs(data)
69			if err != nil {
70				return nil, nil, err
71			}
72			refs, err := AdvRefsToSlice(adv)
73			if err != nil {
74				return nil, nil, err
75			}
76			return refs, &RefService{Protocol: "v1", V1Adv: adv, HeadTarget: headTargetFromAdv(adv)}, nil
77	
78		default:
79			return nil, nil, fmt.Errorf("unsupported protocol mode %q", protocolMode)
80		}
81	}
